#include<bits/stdc++.h>
using namespace std;
int n;
struct node
{
	string s;
	int id;
} a[110];
bool cmp(node x, node y)
{
	if (x.s.size()==y.s.size())
	{
		return x.s>y.s;
	}
	return x.s.size()>y.s.size();
}
int main()
{
    cin>>n;
	for (int i=1;i<=n;i++)
	{
		cin>>a[i].s;
		a[i].id=i;
	}
	sort(a+1,a+n+1,cmp);
	cout<<a[1].id <<"\n"<< a[1].s;
    return 0;
}
